import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    @Test
    void testParse_withValidStringAndFormat_returnsCSVParser() throws IOException {
        String csvData = "header1,header2\nvalue1,value2";
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<org.apache.commons.csv.Assertions> mockedAssertions = Mockito.mockStatic(org.apache.commons.csv.Assertions.class)) {
            // Mock Assertions.notNull to do nothing (no exception)
            mockedAssertions.when(() -> org.apache.commons.csv.Assertions.notNull(any(), anyString())).thenAnswer(invocation -> null);

            CSVParser parser = CSVParser.parse(csvData, format);

            assertNotNull(parser);
            assertFalse(parser.isClosed());
            assertEquals(format, parser.getHeaderMap() == null ? format : parser.getHeaderMap()); // just basic check
        }
    }

    @Test
    void testParse_nullString_throwsException() {
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<org.apache.commons.csv.Assertions> mockedAssertions = Mockito.mockStatic(org.apache.commons.csv.Assertions.class)) {
            mockedAssertions.when(() -> org.apache.commons.csv.Assertions.notNull(null, "string"))
                    .thenThrow(new NullPointerException("string"));

            NullPointerException exception = assertThrows(NullPointerException.class, () -> CSVParser.parse(null, format));
            assertEquals("string", exception.getMessage());
        }
    }

    @Test
    void testParse_nullFormat_throwsException() {
        String csvData = "a,b";

        try (MockedStatic<org.apache.commons.csv.Assertions> mockedAssertions = Mockito.mockStatic(org.apache.commons.csv.Assertions.class)) {
            mockedAssertions.when(() -> org.apache.commons.csv.Assertions.notNull(any(), eq("string"))).thenReturn(null);
            mockedAssertions.when(() -> org.apache.commons.csv.Assertions.notNull(null, "format"))
                    .thenThrow(new NullPointerException("format"));

            NullPointerException exception = assertThrows(NullPointerException.class, () -> CSVParser.parse(csvData, null));
            assertEquals("format", exception.getMessage());
        }
    }
}
